    sifreli_metin = ""
    for karakter in metin:
        if karakter.isalpha():
            ascii_degeri = ord(karakter)
            if karakter.isupper():
                sifreli_metin += chr((ascii_degeri + kaydirma - 65) % 26 + 65)
